// map each merged PR to its linear issue state
const results = prs
  .filter(p => p.closes_linear)
  .map(p => {
    const li = issues.find(i => i.id === p.closes_linear);
    return { pr: p.number, linear: p.closes_linear, state: li?.state };
  })
  .filter(r => r.state && r.state !== 'done');

results;
results.length;
